example.query:
-- 1. Left join with a city filter
SELECT s.name, e.course FROM Students AS s LEFT JOIN Enrollments AS e ON s.id = e.student_id WHERE s.city = 'Delhi';

-- 2. Finding unmatched rows with an added condition
SELECT s.name FROM Students AS s LEFT JOIN Enrollments AS e ON s.id = e.student_id WHERE e.student_id IS NULL AND s.age > 21;

shared_table.create_sql:
CREATE TABLE Enrollments (
  id INTEGER PRIMARY KEY,
  student_id INTEGER,
  course TEXT
);
